#!/usr/bin/env node
"use strict";

const fs = require("fs");
const path = require("path");

const ROOT = process.cwd();
const STAMP = Date.now();
const FILES = [
  {
    "path": "src/lib/discord-command-bridge.ts",
    "base64": ""
  },
  {
    "path": "src/pages/api/discord-interactions.ts",
    "base64": ""
  },
  {
    "path": "src/pages/api/discord-register.ts",
    "base64": ""
  },
  {
    "path": "scripts/test-discord-command-bridge.ts",
    "base64": ""
  }
];

function ensureParent(file) {
  fs.mkdirSync(path.dirname(file), { recursive: true });
}

for (const entry of FILES) {
  const file = path.join(ROOT, entry.path);
  ensureParent(file);

  if (fs.existsSync(file)) {
    const backup = `${file}.bak.${STAMP}`;
    fs.copyFileSync(file, backup);
    console.log(`🧯 Backup: ${path.relative(ROOT, backup)}`);
  }

  fs.writeFileSync(file, Buffer.from(entry.base64, "base64"));
  console.log(`✅ Wrote ${entry.path}`);
}

console.log("");
console.log(`✅ Discord/Twitch bridge installed with 72 Twitch commands.`);
console.log("Next: run focused tests, typecheck and production build.");
